2	\chapter{Mayer--Vietoris long exact sequence for sheaf cohomology with \(k\)-module coefficients}
3	\label{chap:Cohomology_MayerVietoris}
4	
5	This chapter constructs the Mayer--Vietoris long exact sequence for sheaf cohomology valued in \(k\)-modules, and develops the \v{C}ech-acyclicity machinery for affine basic-open covers. Together these provide the categorical engine for the Serre finiteness argument (Phase~A step~6). The carriers \(H^n(X,\mathcal F)\) and \(H^{\prime n}(U,\mathcal F)\) live in Chapter~REF and are imported here.
6	
7	The chapter introduces no protected declarations: every definition, lemma, and instance here is auxiliary, supporting the construction of \(H^1(C,\mathcal O_C)\) in Definition~REF.
8	
9	\section{Functoriality of cohomology in the open variable}
10	\label{sec:hmodule_prime_cohomologyPresheaf}
11	
12	The cohomology-of-an-open carrier \(H^{\prime n}(X,\mathcal F)\) is contravariantly functorial in the open variable \(X\). Assembling this functoriality yields a presheaf
13	\[
14	  X \longmapsto H^{\prime n}(X, \mathcal F),
15	\]
16	and, varying \(\mathcal F\) as well, a bifunctor from sheaves of \(k\)-modules to presheaves of abelian groups. The codomain is the category of abelian groups because \(\Ext\) is always valued there, regardless of the linear enrichment of the source category; the per-fiber \(k\)-module structure is inherited from the reducible wrapper on \(H^{\prime n}\).
17	
18	\begin{definition}\leanok
19	[Cohomology presheaf functor, \(H'\) flavor]
20	  \label{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
21	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheafFunctor}
22	  
23	  Let \(k\) be a field, \(C\) a category equipped with a Grothendieck topology \(J\), and assume sheafification and \(\Ext\) exist for sheaves of \(k\)-modules on \(J\). For \(n \in \mathbb N\), define the cohomology presheaf functor
24	  \[
25	    \mathcal H^{\prime n}(k, J) \;:\; \Sheaf\,J\,(\ModuleCat\,k) \longrightarrow (C^{\op} \longrightarrow \AddCommGrpCat)
26	  \]
27	  by the standard composition of the Yoneda embedding, the free-\(k\)-module functor, sheafification, and the \(n\)-th \(\Ext\) functor.
28	\end{definition}
29	
30	\begin{proof}
31	  
32	  \leanok
33	  The body is a direct categorical composition mirroring the general sheaf-cohomology presheaf functor. Universe pinning is required because the morphism universe of the sheaf category lives one level above the object universe.
34	\end{proof}
35	
36	\begin{definition}\leanok
37	[Cohomology presheaf, \(H'\) flavor]
38	  \label{def:Scheme_HModule_prime_cohomologyPresheaf}
39	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheaf}
40	  
41	  In the setting of Definition~REF, let \(\mathcal F\) be a sheaf of \(k\)-modules. For \(n \in \mathbb N\), define the cohomology presheaf
42	  \[
43	    \mathcal H^{\prime n}(\mathcal F) \;:\; C^{\op} \longrightarrow \AddCommGrpCat
44	  \]
45	  to be the evaluation of the bifunctor at \(\mathcal F\).
46	\end{definition}
47	
48	\begin{proof}
49	  
50	  \leanok
51	  Direct evaluation of the bifunctor at \(\mathcal F\).
52	\end{proof}
53	
54	\begin{remark}
55	  For every object \(X\) of \(C\), the underlying type of \(\mathcal H^{\prime n}(\mathcal F)(X)\) is definitionally equal to \(H^{\prime n}(X, \mathcal F)\). The per-fiber \(k\)-module structure is therefore inherited through the \(H'\) wrapper.
56	\end{remark}
57	
58	\begin{remark}[Lean implementation]
59	  The cohomology presheaf functor is declared as a non-computable definition and the presheaf as a non-computable abbrev, matching the reducibility conventions of the general sheaf-cohomology API. The abbrev form is load-bearing: downstream definitional unfolding needs to see through to the fiber-level \(H'\) carrier.
60	\end{remark}
61	
62	\section{Mayer--Vietoris long exact sequence}
63	\label{sec:hmodule_prime_mayer_vietoris}
64	
65	A Mayer--Vietoris square for a Grothendieck topology \(J\) on a category \(C\) is a pullback square
66	% NOTE: rendered as a 2x2 array for KaTeX (leanblueprint web); the PDF
67	% build renders the same data via tikz-cd if the package is available.
68	\[
69	  \begin{array}{ccc}
70	    X_1 & \longrightarrow & X_2 \\
71	    \downarrow & & \downarrow \\
72	    X_3 & \longrightarrow & X_4
73	  \end{array}
74	\]
75	that is a \(J\)-cover: the pair of morphisms \(X_2 \to X_4\) and \(X_3 \to X_4\) is a covering family, and \(X_1\) is the pullback. For a sheaf \(\mathcal F\), the cohomology groups of the four corners are linked by a long exact sequence whose building blocks are restriction maps, biproduct maps, and a connecting homomorphism.
76	
77	\subsection{The restriction maps}
78	
79	\begin{definition}\leanok
80	[Sum of two restriction maps]
81	  \label{def:Scheme_HModule_prime_toBiprod}
82	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod}
83	  
84	  Let \(S\) be a Mayer--Vietoris square, \(\mathcal F\) a sheaf of \(k\)-modules, and \(n \in \mathbb N\). Define the morphism
85	  \[
86	    \toBiprod \;:\; H^{\prime n}(X_4, \mathcal F) \longrightarrow H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F)
87	  \]
88	  to be the biproduct lift of the two restriction maps induced by \(X_2 \to X_4\) and \(X_3 \to X_4\).
89	\end{definition}
90	
91	\begin{proof}
92	  
93	  \leanok
94	  The biproduct exists because the category of abelian groups has finite biproducts. The morphism is built from the contravariant functoriality of the cohomology presheaf.
95	\end{proof}
96	
97	\begin{definition}\leanok
98	[Difference of two restriction maps]
99	  \label{def:Scheme_HModule_prime_fromBiprod}
100	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod}
101	  
102	  In the same setting, define the morphism
103	  \[
104	    \fromBiprod \;:\; H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F) \longrightarrow H^{\prime n}(X_1, \mathcal F)
105	  \]
106	  to be the biproduct desc of the restriction map \(X_1 \to X_2\) and the additive inverse of the restriction map \(X_1 \to X_3\).
107	\end{definition}
108	
109	\begin{proof}
110	  
111	  \leanok
112	  The negation is taken in the preadditive morphism group of the codomain category. The sign convention encodes the alternating-sum structure of the \v{C}ech complex.
113	\end{proof}
114	
115	\begin{lemma}\leanok
116	[Composition vanishes]
117	  \label{lem:Scheme_HModule_prime_toBiprod_fromBiprod}
118	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_fromBiprod}
119	  
120	  In the setting above,
121	  \[
122	    \fromBiprod \circ \toBiprod \;=\; 0.
123	  \]
124	\end{lemma}
125	
126	\begin{proof}
127	  
128	  \leanok
129	  This is a formal consequence of the biproduct universal property, preadditivity, and the pullback equation \(X_1 \to X_2 \to X_4 = X_1 \to X_3 \to X_4\). Every step is independent of the value category and transfers verbatim from the abelian-group-valued setting.
130	\end{proof}
131	
132	\subsection{The short exact sequence of sheaves}
133	
134	The connecting homomorphism of the Mayer--Vietoris sequence is built from a short exact sequence of sheaves of \(k\)-modules obtained by sheafifying the Yoneda embedding composed with the free-\(k\)-module functor.
135	
136	\begin{definition}\leanok
137	[Free-\(k\)-module functor is left adjoint]
138	  \label{def:Scheme_ModuleCat_free_isLeftAdjoint}
139	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_isLeftAdjoint}
140	  Let \(k\) be a field. The free-\(k\)-module functor \(\Type \to \ModuleCat\,k\) is a left adjoint.
141	\end{definition}
142	
143	\begin{proof}
144	  \leanok
145	  The adjunction is the standard free-forgetful adjunction for \(k\)-modules. The declaration packages the existing adjunction into the typeclass-witness form.
146	\end{proof}
147	
148	\begin{lemma}\leanok
149	[Pushout of free sheaves]
150	  \label{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
151	  \lean{AlgebraicGeometry.Scheme.HModule'_isPushoutModuleCatFreeSheaf}
152	  
153	  Let \(S\) be a Mayer--Vietoris square. The image of \(S\) under the composite functor
154	  \[
155	    \text{Yoneda} \;\circ\; \text{whiskering with }(\ModuleCat.\free\,k) \;\circ\; \presheafToSheaf
156	  \]
157	  is a pushout square in the category of sheaves of \(k\)-modules.
158	\end{lemma}
159	
160	\begin{proof}
161	  
162	  \leanok
163	  The original square is a pushout. Post-composition with the sheafify-compose functor preserves pushouts because the free-\(k\)-module functor is a left adjoint. A canonical isomorphism translates the resulting square into the desired shape.
164	\end{proof}
165	
166	\begin{definition}\leanok
167	[Short complex of free sheaves]
168	  \label{def:Scheme_HModule_prime_shortComplex}
169	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex}
170	  
171	  In the setting of Lemma~REF, define the short complex of sheaves of \(k\)-modules
172	  \[
173	    \mathcal F_1 \xrightarrow{\;f\;} \mathcal F_2 \oplus \mathcal F_3 \xrightarrow{\;g\;} \mathcal F_4,
174	  \]
175	  where \(f\) is the biproduct lift of the two maps induced by \(X_1 \to X_2\) and \(-X_1 \to X_3\), and \(g\) is the biproduct desc of the two maps induced by \(X_2 \to X_4\) and \(X_3 \to X_4\). The composition \(g \circ f = 0\) follows from the cokernel-cofork condition of the pushout.
176	\end{definition}
177	
178	\begin{proof}
179	  
180	  \leanok
181	  The five object and morphism fields are filled directly from the pushout data; the zero field follows from the cokernel cofork condition.
182	\end{proof}
183	
184	\begin{definition}\leanok
185	[Free-\(k\)-module functor preserves monomorphisms]
186	  \label{def:Scheme_ModuleCat_free_preservesMonomorphisms}
187	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_preservesMonomorphisms}
188	  Let \(k\) be a field. The free-\(k\)-module functor preserves monomorphisms.
189	\end{definition}
190	
191	\begin{proof}
192	  \leanok
193	  An injective function between types induces an injective \(k\)-linear map on free modules because the map on finsupp supports is injective. Monomorphism status in the category of \(k\)-modules is equivalent to injectivity.
194	\end{proof}
195	
196	\begin{lemma}\leanok
197	[The first map is mono]
198	  \label{lem:Scheme_HModule_prime_shortComplex_f_mono}
199	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_f_mono}
200	  
201	  In the short complex of Definition~REF, the first map \(f\) is a monomorphism.
202	\end{lemma}
203	
204	\begin{proof}
205	  
206	  \leanok
207	  The map \(f\) followed by the second projection is the free-\(k\)-module functor applied to the monomorphism \(X_1 \to X_3\), which is mono because the free functor preserves monomorphisms. Hence \(f\) itself is mono.
208	\end{proof}
209	
210	\begin{lemma}\leanok
211	[The second map is epi]
212	  \label{lem:Scheme_HModule_prime_shortComplex_g_epi}
213	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_g_epi}
214	  
215	  In the short complex of Definition~REF, the second map \(g\) is an epimorphism.
216	\end{lemma}
217	
218	\begin{proof}
219	  
220	  \leanok
221	  By the pushout lemma, \(g\) is the cokernel of \(f\), and every cokernel is epi.
222	\end{proof}
223	
224	\begin{lemma}\leanok
225	[Exactness at the middle term]
226	  \label{lem:Scheme_HModule_prime_shortComplex_exact}
227	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_exact}
228	  
229	  In the short complex of Definition~REF, exactness holds at the middle term: the image of \(f\) equals the kernel of \(g\).
230	\end{lemma}
231	
232	\begin{proof}
233	  
234	  \leanok
235	  By the pushout lemma, \(g\) is the cokernel of \(f\); a map is its own kernel's cokernel in an abelian category, so exactness holds at the middle term.
236	\end{proof}
237	
238	\begin{lemma}\leanok
239	[The short complex is short exact]
240	  \label{lem:Scheme_HModule_prime_shortComplex_shortExact}
241	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_shortExact}
242	  
243	  The short complex of Definition~REF is short exact: its first map is mono, its second map is epi, and exactness holds at the middle term.
244	\end{lemma}
245	
246	\begin{proof}
247	  
248	  \leanok
249	  Combine Lemma~REF, Lemma~REF, and Lemma~REF.
250	\end{proof}
251	
252	\subsection{The connecting homomorphism and the long exact sequence}
253	
254	\begin{definition}\leanok
255	[Connecting homomorphism]
256	  \label{def:Scheme_HModule_prime_delta}
257	  \lean{AlgebraicGeometry.Scheme.HModule'_δ}
258	  
259	  Let \(S\) be a Mayer--Vietoris square, \(\mathcal F\) a sheaf of \(k\)-modules, and \(n_0, n_1 \in \mathbb N\) with \(n_0 + 1 = n_1\). The connecting homomorphism
260	  \[
261	    \delta \;:\; H^{\prime n_0}(X_1, \mathcal F) \longrightarrow H^{\prime n_1}(X_4, \mathcal F)
262	  \]
263	  is obtained by precomposing the extension class of the short exact sequence of Lemma~REF with the canonical degree-zero map.
264	\end{definition}
265	
266	\begin{proof}
267	  
268	  \leanok
269	  The extension class lives in \(\Ext^1\) of the short exact sequence; precomposing with a map of degree zero and transporting through the additive structure yields the connecting homomorphism as a morphism of abelian groups.
270	\end{proof}
271	
272	\begin{definition}\leanok
273	[Mayer--Vietoris long exact sequence]
274	  \label{def:Scheme_HModule_prime_sequence}
275	  \lean{AlgebraicGeometry.Scheme.HModule'_sequence}
276	  
277	  In the setting of Definition~REF, define the five-term Mayer--Vietoris sequence
278	  \[
279	    H^{\prime n_0}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_0}(X_2, \mathcal F) \oplus H^{\prime n_0}(X_3, \mathcal F) \xrightarrow{\;\fromBiprod\;} H^{\prime n_0}(X_1, \mathcal F) \xrightarrow{\;\delta\;} H^{\prime n_1}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_1}(X_2, \mathcal F) \oplus H^{\prime n_1}(X_3, \mathcal F).
280	  \]
281	\end{definition}
282	
283	\begin{proof}
284	  
285	  \leanok
286	  The sequence is packaged as five composable arrows in the category of abelian groups.
287	\end{proof}
288	
289	\subsection{Comparison with the \(\Ext\) contravariant sequence}
290	
291	The following four lemmas bridge the biproduct structure on the abelian-group side with the \(\Ext\) biproduct additivity, preparing the comparison isomorphism.
292	
293	\begin{lemma}\leanok
294	[Elementwise formula for \(\toBiprod\)]
295	  \label{lem:Scheme_HModule_prime_toBiprod_apply}
296	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_apply}
297	  
298	  For \(y \in H^{\prime n}(X_4, \mathcal F)\),
299	  \[
300	    \toBiprod(y) \;=\; \bigl(\mathrm{restriction}_{X_4 \to X_2}(y),\; \mathrm{restriction}_{X_4 \to X_3}(y)\bigr).
301	  \]
302	\end{lemma}
303	
304	\begin{proof}
305	  
306	  \leanok
307	  Follows from the definition of \(\toBiprod\) as a biproduct lift and the naturality of the biproduct isomorphism with the product.
308	\end{proof}
309	
310	\begin{lemma}\leanok
311	[Elementwise formula for \(\fromBiprod\)]
312	  \label{lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply}
313	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod_biprodIsoProd_inv_apply}
314	  
315	  For \(y_2 \in H^{\prime n}(X_2, \mathcal F)\) and \(y_3 \in H^{\prime n}(X_3, \mathcal F)\),
316	  \[
317	    \fromBiprod(y_2, y_3) \;=\; \mathrm{restriction}_{X_2 \to X_1}(y_2) \;-\; \mathrm{restriction}_{X_3 \to X_1}(y_3).
318	  \]
319	\end{lemma}
320	
321	\begin{proof}
322	  
323	  \leanok
324	  Follows from the definition of \(\fromBiprod\) as a biproduct desc and the concrete description of the biproduct isomorphism.
325	\end{proof}
326	
327	\begin{lemma}\leanok
328	[\(\Ext\) biproduct bridge for \(\toBiprod\)]
329	  \label{lem:Scheme_HModule_prime_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply}
330	  \lean{AlgebraicGeometry.Scheme.HModule'_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply}
331	  
332	  Bridges the abelian-group biproduct isomorphism and the \(\Ext\) biproduct additivity for the \(\toBiprod\) morphism.
333	\end{lemma}
334	
335	\begin{proof}
336	  
337	  \leanok
338	  Injects through the additive equivalence and closes by categorical discharge.
339	\end{proof}
340	
341	\begin{lemma}\leanok
342	[\(\Ext\) biproduct bridge for \(\fromBiprod\)]
343	  \label{lem:Scheme_HModule_prime_mk_zero_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
344	  \lean{AlgebraicGeometry.Scheme.HModule'_mk₀_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
345	  
346	  Bridges the same machinery for the \(\fromBiprod\) morphism.
347	\end{lemma}
348	
349	\begin{proof}
350	  
351	  \leanok
352	  Obtains a pair from the biproduct surjectivity, then rewrites through the concrete formulas and closes by categorical discharge.
353	\end{proof}
354	
355	\begin{definition}\leanok
356	[Comparison isomorphism]
357	  \label{def:Scheme_HModule_prime_sequenceIso}
358	  \lean{AlgebraicGeometry.Scheme.HModule'_sequenceIso}
359	  
360	  The Mayer--Vietoris sequence of Definition~REF is canonically isomorphic to the \(\Ext\) contravariant sequence applied to the short exact sequence of Lemma~REF.
361	\end{definition}
362	
363	\begin{proof}
364	  
365	  \leanok
366	  The isomorphism is built componentwise: identity maps on the bare terms, and the composition of the biproduct isomorphism with the \(\Ext\) biproduct additivity (in the appropriate direction) on the biproduct terms. The five compatibility squares close via the four auxiliary lemmas above and the definition of the connecting homomorphism.
367	\end{proof}
368	
369	\subsection{Exactness}
370	
371	% NOTE: classical Mayer--Vietoris long exact sequence in sheaf
372	% cohomology; see Hartshorne, *Algebraic Geometry*, Ex.~III.4.6
373	% (TOC: `references/hartshorne-ag.md`) and Stacks Tag~\textbf{03B0}
374	% (Section 21.50 ``Mayer-Vietoris''). The abstract / \(k\)-module-valued
375	% repackaging here mirrors Mathlib's
376	% \texttt{CategoryTheory.MayerVietorisSquare} infrastructure.
377	\begin{theorem}\leanok
378	[Mayer--Vietoris exactness]
379	  \label{thm:Scheme_HModule_prime_sequence_exact}
380	  \lean{AlgebraicGeometry.Scheme.HModule'_sequence_exact}
381	  
382	  The Mayer--Vietoris sequence of Definition~REF is exact.
383	\end{theorem}
384	
385	\begin{proof}
386	  
387	  \leanok
388	  Transport exactness along the comparison isomorphism of Definition~REF. The \(\Ext\) contravariant sequence is exact by the general exactness theorem for \(\Ext\) applied to a short exact sequence.
389	\end{proof}
390	
391	\begin{lemma}\leanok
392	[Connecting homomorphism annihilates \(\toBiprod\)]
393	  \label{lem:Scheme_HModule_prime_delta_toBiprod}
394	  \lean{AlgebraicGeometry.Scheme.HModule'_δ_toBiprod}
395	  
396	  In the setting above,
397	  \[
398	    \delta \circ \toBiprod \;=\; 0.
399	  \]
400	\end{lemma}
401	
402	\begin{proof}
403	  
404	  \leanok
405	  Immediate from exactness at the third term of the sequence.
406	\end{proof}
407	
408	\begin{lemma}\leanok
409	[\(\fromBiprod\) annihilates the connecting homomorphism]
410	  \label{lem:Scheme_HModule_prime_fromBiprod_delta}
411	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod_δ}
412	  
413	  In the setting above,
414	  \[
415	    \fromBiprod \circ \delta \;=\; 0.
416	  \]
417	\end{lemma}
418	
419	\begin{proof}
420	  
421	  \leanok
422	  Immediate from exactness at the second term of the sequence.
423	\end{proof}
424	
425	\begin{remark}[Build-out completion]
426	  Theorem~REF closes the abstract Mayer--Vietoris long exact sequence for sheaves of \(k\)-modules. The sequence mirrors the abelian-group-valued analogue line by line, with the free-\(k\)-module functor in place of the free-abelian-group functor. The full infrastructure is now ready to be specialised to geometric covers.
427	\end{remark}
428	
429	\section{Two-affine open covers}
430	\label{sec:scheme_affineCoverMVSquare}
431	
432	A quasi-compact separated scheme \(X\) over \(k\) admits an open cover by two affines \(U_1, U_2\) whose intersection \(U_1 \cap U_2\) is again affine. Such a cover is the geometric input for the abstract Mayer--Vietoris machine. This section packages the data into a bundled structure and specialises the LES.
433	
434	\begin{definition}\leanok
435	[Two-affine Mayer--Vietoris square]
436	  \label{def:Scheme_AffineCoverMVSquare}
437	  \lean{AlgebraicGeometry.Scheme.AffineCoverMVSquare}
438	  
439	  Let \(X\) be a scheme. A two-affine Mayer--Vietoris square on \(X\) consists of two open subschemes \(U_1, U_2\) of \(X\) such that \(U_1\), \(U_2\), and \(U_1 \cap U_2\) are affine, together with the hypothesis \(U_1 \cup U_2 = X\).
440	\end{definition}
441	
442	\begin{definition}\leanok
443	[Underlying Mayer--Vietoris square]
444	  \label{def:Scheme_AffineCoverMVSquare_toMayerVietorisSquare}
445	  \lean{AlgebraicGeometry.Scheme.AffineCoverMVSquare.toMayerVietorisSquare}
446	  
447	  Given a two-affine cover \(S\) of \(X\), the underlying abstract Mayer--Vietoris square has corners \(X_1 = U_1 \cap U_2\), \(X_2 = U_1\), \(X_3 = U_2\), \(X_4 = U_1 \cup U_2\).
448	\end{definition}
449	
450	% NOTE (DAG iter-266): the umbrella ``Corner identifications'' lemma
451	% (formerly \label{lem:Scheme_AffineCoverMVSquare_corners}) was removed.
452	% It carried no \lean{} target, no consumers (\uses{}/\cref{}), and merely
453	% restated the four individual corner identifications below
454	% (\cref{lem:Scheme_AffineCoverMVSquare_X1}--\cref{lem:Scheme_AffineCoverMVSquare_X4}),
455	% each of which has its own Lean declaration and proof. It was an isolated
456	% ∞-node (no statement effort, no Lean link); deleting it removes the hole
457	% without losing content.
458	
459	\begin{lemma}\leanok
460	[Corner identification, \(X_1\)]
461	  \label{lem:Scheme_AffineCoverMVSquare_X1}
462	  \lean{AlgebraicGeometry.Scheme.AffineCoverMVSquare.toMayerVietorisSquare_toSquare_X₁}
463	  
464	  \(S.\toMayerVietorisSquare.X_1 = S.U_1 \cap S.U_2\).
465	\end{lemma}
466	
467	\begin{proof}
468	
469	
470	\leanok
471	  By definitional equality from the construction of the underlying Mayer--Vietoris square.
472	\end{proof}
473	
474	\begin{lemma}\leanok
475	[Corner identification, \(X_2\)]
476	  \label{lem:Scheme_AffineCoverMVSquare_X2}
